create table training_sessions (
    session_id       number generated by default as identity minvalue 1 maxvalue 9999999999999999999999999999 increment by 1 cache 20
    noorder nocycle nokeep noscale not null enable,
    team_id          number not null enable,
    lead_coach_id    number,
    session_date     date not null enable,
    session_type     varchar2(40 byte) not null enable,
    duration_minutes number(4, 0) not null enable,
    location_name    varchar2(120 byte),
    session_status   varchar2(20 byte) default 'PLANNED' not null enable
);

alter table training_sessions
    add constraint training_duration_ck check ( duration_minutes between 15 and 300 ) enable;

alter table training_sessions
    add constraint training_sessions_pk primary key ( session_id )
        using index enable;

alter table training_sessions
    add constraint training_status_ck
        check ( session_status in ( 'PLANNED', 'COMPLETED', 'CANCELLED' ) ) enable;


